import{c as t,Q as o,j as d,m as c}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"GPT-Image-2 绘图教程","description":"","frontmatter":{},"headers":[],"relativePath":"paint/GPTImage.md","filePath":"paint/GPTImage.md","lastUpdated":1779875536000}'),a={name:"paint/GPTImage.md"};function i(r,e,s,n,p,l){return o(),d("div",null,[...e[0]||(e[0]=[c(`<h1 id="gpt-image-2-绘图教程" tabindex="-1">GPT-Image-2 绘图教程 <a class="header-anchor" href="#gpt-image-2-绘图教程" aria-label="Permalink to &quot;GPT-Image-2 绘图教程&quot;">​</a></h1><hr><h2 id="前置准备" tabindex="-1">前置准备 <a class="header-anchor" href="#前置准备" aria-label="Permalink to &quot;前置准备&quot;">​</a></h2><p><code>gpt-image-2</code> 模型属于 <strong>Sora 分组</strong> ，使用前需要创建密钥分组为 <code>sora</code> 的令牌。</p><p>参照 <a href="/register/4-token.html">创建密钥分组</a> 教程创建令牌，<strong>分组选择<code>sora</code></strong>。</p><h2 id="调用方式" tabindex="-1">调用方式 <a class="header-anchor" href="#调用方式" aria-label="Permalink to &quot;调用方式&quot;">​</a></h2><p>OpenAI 官方文档把图片相关能力分成 Responses API、Images API、Chat Completions API 三类。对 Packy 的 <code>gpt-image-2</code> 来说，出图请优先使用 Images API。</p><table tabindex="0"><thead><tr><th>API</th><th>OpenAI 官方用途</th><th>Packy <code>gpt-image-2</code> 使用建议</th><th>建议</th></tr></thead><tbody><tr><td>Responses API</td><td>分析图片，并把图片作为输入；也可以通过工具生成图片输出</td><td>不支持作为 <code>gpt-image-2</code> 的出图入口。需要出图请使用 Images API。</td><td>不支持</td></tr><tr><td>Images API</td><td>生成图片，也可以上传图片作为输入进行编辑</td><td>支持文生图和图片编辑，是 <code>gpt-image-2</code> 的推荐调用方式。</td><td>推荐</td></tr><tr><td>Chat Completions API</td><td>分析图片输入，并生成文本或音频</td><td>不支持作为 <code>gpt-image-2</code> 的出图入口；<code>size</code>、<code>quality</code>、<code>output_format</code> 等 Images 参数不会按图片接口生效。</td><td>不支持</td></tr></tbody></table><h3 id="方式一-images-api-推荐" tabindex="-1">方式一：Images API（推荐） <a class="header-anchor" href="#方式一-images-api-推荐" aria-label="Permalink to &quot;方式一：Images API（推荐）&quot;">​</a></h3><p>Images API 是 <code>gpt-image-2</code> 的推荐出图方式，分为文生图和图片编辑两个接口：</p><ul><li>文生图：<code>POST https://api.suirenai.com/v1/images/generations</code></li><li>图片编辑 / 图生图：<code>POST https://api.suirenai.com/v1/images/edits</code></li></ul><p>每个接口下面都按“接口实例 → 参数介绍”的格式说明。对新手来说，只要先照着示例传 <code>model</code>、<code>prompt</code>，并把 <code>n</code> 设为 <code>1</code>；需要上传图片时再使用 <code>image</code> 字段即可。</p><p>推荐用法</p><p>文生图使用 <code>/v1/images/generations</code>，上传参考图进行图片编辑使用 <code>/v1/images/edits</code>。</p><h4 id="文生图-v1-images-generations" tabindex="-1">文生图：<code>/v1/images/generations</code> <a class="header-anchor" href="#文生图-v1-images-generations" aria-label="Permalink to &quot;文生图：\`/v1/images/generations\`&quot;">​</a></h4><h5 id="接口实例" tabindex="-1">接口实例 <a class="header-anchor" href="#接口实例" aria-label="Permalink to &quot;接口实例&quot;">​</a></h5><pre><code>curl --location &#39;https://api.suirenai.com/v1/images/generations&#39; \\
--header &#39;Content-Type: application/json&#39; \\
--header &#39;Authorization: Bearer 你的Sora分组密钥&#39; \\
--header &#39;Accept: */*&#39; \\
--header &#39;Host: www.suirenai.com&#39; \\
--header &#39;Connection: keep-alive&#39; \\
--data &#39;{
    &quot;model&quot;: &quot;gpt-image-2&quot;,
    &quot;prompt&quot;: &quot;一只橘猫戴着橙色围巾抱着水獭，温暖插画风格&quot;,
    &quot;size&quot;: &quot;3840x2160&quot;,
    &quot;quality&quot;: &quot;high&quot;,
    &quot;output_format&quot;: &quot;png&quot;,
    &quot;response_format&quot;: &quot;url&quot;,
    &quot;n&quot;: 1
}&#39;
</code></pre><h5 id="文生图参数" tabindex="-1">文生图参数 <a class="header-anchor" href="#文生图参数" aria-label="Permalink to &quot;文生图参数&quot;">​</a></h5><table tabindex="0"><thead><tr><th>参数</th><th>类型</th><th>支持情况</th><th>说明</th></tr></thead><tbody><tr><td><code>model</code></td><td>string</td><td>支持</td><td>固定填写 <code>gpt-image-2</code>。</td></tr><tr><td><code>prompt</code></td><td>string</td><td>支持</td><td>图片描述提示词，建议写清楚主体、场景、风格、比例和文字内容。</td></tr><tr><td><code>n</code></td><td>integer</td><td>仅支持 <code>1</code></td><td>只支持一次返回 1 张图。<s><code>n: 2</code>、<code>n: 4</code></s> 这类多图数量不支持。</td></tr><tr><td><code>size</code></td><td>string</td><td>支持</td><td>支持 <code>auto</code> 和符合限制的尺寸，如 <code>1024x1024</code>、<code>1536x1024</code>、<code>1024x1536</code>、<code>1536x864</code>、<code>3840x2160</code>。</td></tr><tr><td><code>quality</code></td><td>string</td><td>支持</td><td>可选 <code>low</code>、<code>medium</code>、<code>high</code>、<code>auto</code>。草稿图可以用 <code>low</code>，正式出图可以用 <code>high</code>。</td></tr><tr><td><code>response_format</code></td><td>string</td><td>支持</td><td>可选 <code>url</code>、<code>b64_json</code>。默认建议用 <code>url</code>；<code>b64_json</code> 适合程序自行保存图片。</td></tr><tr><td><code>output_format</code></td><td>string</td><td>部分支持</td><td>推荐 <code>png</code> 或 <code>jpeg</code>。<s><code>webp</code></s> 不建议使用。</td></tr><tr><td><code>output_compression</code></td><td>integer</td><td>支持</td><td>只建议在 <code>output_format</code> 为 <code>jpeg</code> 时使用，取值 <code>0</code> 到 <code>100</code>。</td></tr><tr><td><code>background</code></td><td>string</td><td>部分支持</td><td>建议使用默认值或 <code>opaque</code>。<s><code>transparent</code></s> 不支持。</td></tr><tr><td><code>moderation</code></td><td>string</td><td>支持</td><td>可选 <code>auto</code>、<code>low</code>。这是安全审核参数，不会直接改变画面风格；不确定时保持默认即可。</td></tr><tr><td><code>user</code></td><td>string</td><td>支持</td><td>可选，用于标记你自己的终端用户或业务来源，普通调用可以不传。</td></tr><tr><td><s><code>stream</code></s></td><td>boolean</td><td>不支持</td><td>请不要开启。</td></tr><tr><td><s><code>partial_images</code></s></td><td>integer</td><td>不支持</td><td>依赖 <code>stream</code> 的中间图返回能力，不支持。</td></tr><tr><td><s><code>style</code></s></td><td>string</td><td>不建议使用</td><td>这是旧模型常见参数，<code>gpt-image-2</code> 不需要传。</td></tr></tbody></table><h4 id="图片编辑-图生图-v1-images-edits" tabindex="-1">图片编辑 / 图生图：<code>/v1/images/edits</code> <a class="header-anchor" href="#图片编辑-图生图-v1-images-edits" aria-label="Permalink to &quot;图片编辑 / 图生图：\`/v1/images/edits\`&quot;">​</a></h4><p><code>/v1/images/edits</code> 使用 <code>multipart/form-data</code> 上传图片。<code>image</code> 是二进制图片文件，<code>prompt</code> 写清楚希望怎么修改图片。</p><h5 id="接口实例-1" tabindex="-1">接口实例 <a class="header-anchor" href="#接口实例-1" aria-label="Permalink to &quot;接口实例&quot;">​</a></h5><pre><code>curl --location &#39;https://api.suirenai.com/v1/images/edits&#39; \\
--header &#39;Authorization: Bearer 你的Sora分组密钥&#39; \\
--header &#39;Accept: */*&#39; \\
--form &#39;model=&quot;gpt-image-2&quot;&#39; \\
--form &#39;prompt=&quot;把图片里的主体保留，在右上角加一枚红色小印章，印章上写 DEMO&quot;&#39; \\
--form &#39;image=@&quot;/path/to/your-image.jpg&quot;&#39; \\
--form &#39;size=&quot;1024x1024&quot;&#39; \\
--form &#39;quality=&quot;high&quot;&#39; \\
--form &#39;output_format=&quot;png&quot;&#39; \\
--form &#39;response_format=&quot;url&quot;&#39;
</code></pre><h5 id="图片编辑参数" tabindex="-1">图片编辑参数 <a class="header-anchor" href="#图片编辑参数" aria-label="Permalink to &quot;图片编辑参数&quot;">​</a></h5><table tabindex="0"><thead><tr><th>参数</th><th>类型</th><th>支持情况</th><th>说明</th></tr></thead><tbody><tr><td><code>model</code></td><td>string</td><td>支持</td><td>固定填写 <code>gpt-image-2</code>。</td></tr><tr><td><code>prompt</code></td><td>string</td><td>支持</td><td>写清楚要保留什么、修改什么、最终希望得到什么。</td></tr><tr><td><code>image</code></td><td>file</td><td>支持</td><td>必填，上传要编辑的图片二进制文件。建议一次只上传 1 张图片。</td></tr><tr><td><code>mask</code></td><td>file</td><td>支持</td><td>可选，局部修改时可传 PNG mask；不传则按整图编辑理解。</td></tr><tr><td><code>n</code></td><td>integer</td><td>仅支持 <code>1</code></td><td>只支持一次返回 1 张图。<s>多张结果</s> 不支持。</td></tr><tr><td><code>size</code></td><td>string</td><td>支持</td><td>同文生图，支持 <code>auto</code> 和符合限制的尺寸。</td></tr><tr><td><code>quality</code></td><td>string</td><td>支持</td><td>可选 <code>low</code>、<code>medium</code>、<code>high</code>、<code>auto</code>。</td></tr><tr><td><code>response_format</code></td><td>string</td><td>支持</td><td>可选 <code>url</code>、<code>b64_json</code>。默认建议用 <code>url</code>。</td></tr><tr><td><code>output_format</code></td><td>string</td><td>部分支持</td><td>推荐 <code>png</code> 或 <code>jpeg</code>。<s><code>webp</code></s> 不建议使用。</td></tr><tr><td><code>output_compression</code></td><td>integer</td><td>支持</td><td>只建议在 <code>output_format</code> 为 <code>jpeg</code> 时使用，取值 <code>0</code> 到 <code>100</code>。</td></tr><tr><td><code>background</code></td><td>string</td><td>部分支持</td><td>建议使用默认值或 <code>opaque</code>。<s><code>transparent</code></s> 不支持。</td></tr><tr><td><code>moderation</code></td><td>string</td><td>支持</td><td>可选 <code>auto</code>、<code>low</code>。这是安全审核参数，不会直接改变画面风格。</td></tr><tr><td><code>input_fidelity</code></td><td>string</td><td>支持</td><td>图片编辑时可传 <code>high</code>，用于尽量保留原图主体和细节。</td></tr><tr><td><code>user</code></td><td>string</td><td>支持</td><td>可选，普通调用可以不传。</td></tr><tr><td><s><code>stream</code></s></td><td>boolean</td><td>不支持</td><td>请不要开启。</td></tr><tr><td><s><code>partial_images</code></s></td><td>integer</td><td>不支持</td><td>依赖 <code>stream</code> 的中间图返回能力，不支持。</td></tr></tbody></table><p>如果需要局部修改，可以额外传 <code>mask</code>。<code>mask</code> 建议使用 PNG 图片，透明区域表示允许模型重点修改的位置；不传 <code>mask</code> 时，模型会根据提示词对整张图进行编辑。</p><h4 id="通用说明" tabindex="-1">通用说明 <a class="header-anchor" href="#通用说明" aria-label="Permalink to &quot;通用说明&quot;">​</a></h4><h5 id="尺寸与质量" tabindex="-1">尺寸与质量 <a class="header-anchor" href="#尺寸与质量" aria-label="Permalink to &quot;尺寸与质量&quot;">​</a></h5><ul><li><p>常用尺寸（Popular sizes）</p><ul><li><strong>1024 × 1024</strong> ：正方形</li><li><strong>1536 × 1024</strong> ：横向</li><li><strong>1024 × 1536</strong> ：纵向</li><li><strong>2048 × 2048</strong> ：2K 正方形</li><li><strong>2048 × 1152</strong> ：2K 横向</li><li><strong>3840 × 2160</strong> ：4K 横向</li><li><strong>2160 × 3840</strong> ：4K 纵向</li><li><strong>auto</strong> ：自动（默认）</li></ul></li><li><p>尺寸限制（Size constraints）</p><ul><li>最大边长必须 <strong>小于或等于 3840 像素</strong></li><li>宽和高都必须是 <strong>16 的倍数</strong></li><li>长边与短边的比例 <strong>不能超过 3:1</strong></li><li>总像素数必须 <strong>不少于 655,360</strong> ，且 <strong>不超过 8,294,400</strong></li></ul></li><li><p>质量选项（Quality options）</p><ul><li><strong>low</strong> ：低质量</li><li><strong>medium</strong> ：中等质量</li><li><strong>high</strong> ：高质量</li><li><strong>auto</strong> ：自动（默认）</li></ul></li></ul><p>参数怎么选</p><ul><li>最简单文生图：只传 <code>model</code>、<code>prompt</code>，并把 <code>n</code> 设为 <code>1</code>。</li><li>想要更高清晰度：可以加 <code>quality: &quot;high&quot;</code>。</li><li>想控制尺寸：加 <code>size</code>，比如 <code>1024x1024</code> 或 <code>1536x1024</code>。</li><li>想拿图片链接：使用默认 <code>response_format: &quot;url&quot;</code>。</li><li>想让程序自己保存图片：使用 <code>response_format: &quot;b64_json&quot;</code>。</li><li>不要把 <code>n</code> 设置成大于 <code>1</code>，多张图片需要自己循环请求。</li></ul><h5 id="返回结果" tabindex="-1">返回结果 <a class="header-anchor" href="#返回结果" aria-label="Permalink to &quot;返回结果&quot;">​</a></h5><p>默认返回图片下载地址：</p><pre><code>{
  &quot;created&quot;: 1776923999,
  &quot;data&quot;: [
    {
      &quot;url&quot;: &quot;https://external-resources.suirenai.com/file_download/xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx&quot;,
      &quot;revised_prompt&quot;: &quot;...&quot;
    }
  ]
}
</code></pre><p>返回的 <code>url</code> 即为生成的图片地址，直接访问即可下载。<code>revised_prompt</code> 是模型实际使用前改写过的提示词，看到它是正常现象，不是报错。</p><p>如果请求里传了 <code>&quot;response_format&quot;: &quot;b64_json&quot;</code>，返回内容会变成 Base64 图片数据：</p><pre><code>{
  &quot;created&quot;: 1776923999,
  &quot;data&quot;: [
    {
      &quot;b64_json&quot;: &quot;iVBORw0KGgoAAAANSUhEUgAA...&quot;,
      &quot;revised_prompt&quot;: &quot;...&quot;
    }
  ]
}
</code></pre><p>这时响应里通常没有 <code>url</code>，需要客户端自己把 <code>b64_json</code> 解码成图片文件。<code>url</code> 和 <code>b64_json</code> 两种返回方式都会包含 <code>revised_prompt</code>。普通用户更推荐使用默认的 <code>url</code>，最容易保存和分享。</p><h3 id="方式二-responses-api-不支持" tabindex="-1">方式二：Responses API（不支持） <a class="header-anchor" href="#方式二-responses-api-不支持" aria-label="Permalink to &quot;方式二：Responses API（不支持）&quot;">​</a></h3><p>不支持</p><p>Packy 的 <code>gpt-image-2</code> 不支持通过 <code>/v1/responses</code> 出图。请不要使用 <code>image_generation</code> 工具、<code>input</code> 或 <code>input_image</code> 来调用 <code>gpt-image-2</code> 生成图片。</p><p>需要文生图请使用 <code>/v1/images/generations</code>；需要上传图片编辑请使用 <code>/v1/images/edits</code>。</p><h3 id="方式三-chat-completions-api-不支持" tabindex="-1">方式三：Chat Completions API（不支持） <a class="header-anchor" href="#方式三-chat-completions-api-不支持" aria-label="Permalink to &quot;方式三：Chat Completions API（不支持）&quot;">​</a></h3><p>不支持</p><p>Packy 的 <code>gpt-image-2</code> 不支持通过 <code>/v1/chat/completions</code> 出图。请不要把 <code>messages</code>、<code>image_url</code>、<code>size</code>、<code>quality</code>、<code>output_format</code> 等参数放到 Chat Completions 里调用图片生成。</p><p>如果使用 Cherry Studio，请切换到“绘画”应用，并确保端点类型是 <code>图像生成（OpenAI）</code>。</p><p>给开发者</p><p>如果你的客户端只支持 Chat Completions，并且必须接入图片能力，建议优先改为支持 OpenAI Images API。不要把 <code>/v1/chat/completions</code> 当成 <code>/v1/images/generations</code> 的替代品。</p><h2 id="在-cherry-studio-中使用" tabindex="-1">在 Cherry Studio 中使用 <a class="header-anchor" href="#在-cherry-studio-中使用" aria-label="Permalink to &quot;在 Cherry Studio 中使用&quot;">​</a></h2><ol><li><p>参照 <a href="/register/4-token.html">创建密钥分组</a> 一章的教程，创建<strong>密钥分组</strong> 为 <code>sora</code> 的令牌。创建好令牌后，点击复制按钮，将 API Key 复制到剪切板。</p></li><li><p>访问 <a href="https://www.cherry-ai.com/" target="_blank" rel="noreferrer">Cherry Studio</a> 官网下载并安装软件。</p></li><li><p>打开 Cherry Studio，点击左下角设置按钮，进入 <code>模型服务</code> 页面，点击底部的 <code>添加</code> 按钮新增提供商。</p></li><li><p>在添加提供商窗口中填写提供商名称，例如 <code>suirenai-gpt-image-2</code>，<code>提供商类型</code> 选择 <code>New API</code>，然后点击 <code>确定</code>。</p></li></ol><p><img src="https://docs.packyapi.com/assets/image/Paint/gpt-image-2/01.webp" alt=""></p><ol start="5"><li>在左侧列表中找到刚添加的提供商，将第 1 步复制的 <code>sora</code> 分组 API Key 填入 <code>API 密钥</code>，<code>API 地址</code> 填写 <code>https://www.suirenai.com</code>。</li></ol><p><img src="https://docs.packyapi.com/assets/image/Paint/gpt-image-2/02.webp" alt=""></p><ol start="6"><li><p>点击模型区域右侧的 <code>获取模型列表</code>，刷新后添加 <code>gpt-image-2</code> 模型。添加完成后，可以在提供商配置页中看到模型列表里已经出现 <code>gpt-image-2</code>。</p></li><li><p>点击 <code>gpt-image-2</code> 右侧的编辑按钮，进入编辑模型窗口，将 <code>端点类型</code> 设置为 <code>图像生成（OpenAI）</code>，然后点击 <code>保存</code>。</p></li></ol><p><img src="https://docs.packyapi.com/assets/image/Paint/gpt-image-2/03.webp" alt=""></p><ol start="8"><li>回到首页，点击顶部的 <code>+</code> 按钮，在应用列表中选择 <code>绘画</code>。</li></ol><p><img src="https://docs.packyapi.com/assets/image/Paint/gpt-image-2/04.webp" alt=""></p><ol start="9"><li>进入绘画页面后，左侧 <code>提供商</code> 选择刚才添加的供应商，<code>模型</code> 选择 <code>gpt-image-2</code>。首次使用建议先将 <code>图片尺寸</code>、<code>质量</code>、<code>敏感度</code> 等选项保持为 <code>自动</code>，<code>生成数量</code> 保持为 <code>1</code>。</li></ol><p><img src="https://docs.packyapi.com/assets/image/Paint/gpt-image-2/05.webp" alt=""></p><ol start="10"><li><p>如果只需要根据提示词生成图片，顶部选择 <code>绘图</code> 模式，输入提示词后点击发送按钮即可开始生成。</p></li><li><p>如果需要上传参考图进行图生图或局部修改，顶部切换到 <code>编辑</code> 模式，在左侧 <code>输入图片</code> 中上传参考图，再输入修改要求后点击发送按钮。</p></li></ol><p><img src="https://docs.packyapi.com/assets/image/Paint/gpt-image-2/06.webp" alt=""></p><p>使用建议</p><ul><li><code>API 地址</code> 直接填写 <code>https://www.suirenai.com</code> 即可，Cherry Studio 会自动拼接兼容端点，无需手动补 <code>/v1</code>。</li><li>如果模型列表中没有 <code>gpt-image-2</code>，请先在 <code>管理</code> 中刷新模型；如果仍无法正常绘图，请检查 <code>端点类型</code> 是否为 <code>图像生成（OpenAI）</code>。</li><li>使用 <code>绘图</code> 模式可以进行文生图；使用 <code>编辑</code> 模式可以上传参考图进行图生图或局部修改。</li><li>如果你在普通对话页中直接调用 <code>gpt-image-2</code>，建议关闭 <code>流式输出</code>，避免返回内容解析异常。使用 <code>绘画</code> 应用时通常不需要额外处理。</li></ul><h3 id="可能出现的问题" tabindex="-1">可能出现的问题 <a class="header-anchor" href="#可能出现的问题" aria-label="Permalink to &quot;可能出现的问题&quot;">​</a></h3><p>如果 Cherry Studio 弹出 <code>Failed to fetch</code>，通常是请求连接被中断，可能与本机代理或网络环境有关。可以先检查代理设置，确认 Cherry Studio 能正常访问 <code>https://www.suirenai.com</code> 后再重试。</p><p><img src="https://docs.packyapi.com/assets/image/Paint/gpt-image-2/07.webp" alt=""></p><p>如果 Cherry Studio 弹出 <code>Unexpected token &#39;&lt;&#39;, &quot;&lt;html&gt;&lt;h&quot;... is not valid JSON</code>，通常是请求过程中收到了 Cloudflare 等页面内容，客户端按 JSON 解析时显示异常。遇到这种情况可以直接重试，或稍后再重新生成。</p><p><img src="https://docs.packyapi.com/assets/image/Paint/gpt-image-2/08.webp" alt=""></p><h2 id="特别注意-长连接与代理设置" tabindex="-1">特别注意：长连接与代理设置 <a class="header-anchor" href="#特别注意-长连接与代理设置" aria-label="Permalink to &quot;特别注意：长连接与代理设置&quot;">​</a></h2><p>无论是直接通过 API 调用，还是在 Cherry Studio 等客户端程序中使用 <code>gpt-image-2</code>，图片生成请求通常都比普通聊天请求耗时更久，尤其是使用编辑模式、高清质量或高分辨率尺寸时。如果本机代理、网络工具或中间网关对长连接有限制，可能会在 60 秒左右主动断开连接，表现为 API 请求超时、没有返回内容，或客户端提示 <code>Failed to fetch</code>。</p><p>下面以 Cherry Studio 的编辑模式为例，长连接中断时程序侧通常会直接弹出 <code>Failed to fetch</code>；在开发者工具中，也可以看到 <code>edits</code> 请求停在 1 分钟左右。直接调用 API 时虽然界面提示不同，但问题本质相同，都是连接在图片生成完成前被中途断开。</p><p><img src="https://docs.packyapi.com/assets/image/Paint/gpt-image-2/09.webp" alt=""></p><p>如果确认是代理导致连接被中断，建议将本站域名 <code>suirenai.com</code> 加入代理工具的直连或白名单规则，让访问 Suirenai 时不再经过代理。不同代理软件的设置入口可能不同，核心是添加类似 <code>domain:suirenai.com</code> 的域名规则。</p><p><img src="https://docs.packyapi.com/assets/image/Paint/gpt-image-2/10.webp" alt=""></p><p>放行后，同类请求可以等待更久并正常返回。下图中请求在约 1.6 分钟后返回图片；如果使用更高分辨率或更高质量选项，生成时间还可能继续增加。为了减少不可控的网络中断，建议绘图请求尽量直连 <code>suirenai.com</code>，不要经过会限制长连接的代理或中转网络。</p><p><img src="https://docs.packyapi.com/assets/image/Paint/gpt-image-2/11.webp" alt=""></p>`,76)])])}const u=t(a,[["render",i]]);export{m as __pageData,u as default};
